/// <summary>
/// The <c>FWFTextBlockEventHandler_Trans_PoConfirm</c> class handles the functionality for extended texts on purchase orders.
/// </summary>
class FWFTextBlockEventHandler_Trans_PoConfirm extends FWFTextBlockEventHandler_Trans
{    
}

Method.Source:
/// <summary>
/// Creates a new <c>FWFTextBlockEventHandler_Trans_PoConfirm</c> instance.
/// </summary>
/// <returns>The <c>FWFTextBlockEventHandler_Trans_PoConfirm</c> instance.</returns>
public static FWFTextBlockEventHandler_Trans_PoConfirm construct()
{
    return new FWFTextBlockEventHandler_Trans_PoConfirm();
}

/// <summary>
/// Find the source record from target record.
/// </summary>
/// <returns>A <c>Common</c> table.</returns>
protected Common findSourceRecord()
{
    Common sourceRecord;

    switch (targetRecord.TableId)
    {
        case tableNum(PurchLineHistory):
            PurchLineHistory purchLineHistory = targetRecord as PurchLineHistory;
            sourceRecord = purchLineHistory.purchLine();
            break;

        default:
            sourceRecord = super();
    }

    return sourceRecord;
}

/// <summary>
/// A new version of an purchase order was created, so copy the texts to the new version.
/// </summary>
protected void runInsert()
{
    PurchLineAllVersions purchLineAllVersions;
    PurchTableVersion purchTableVersion;
    RecId purchTableVersionRecId = this.parmTargetRecord().RecId;
    PurchLine purchLineSource;

    while select RecId from purchTableVersion
        where purchTableVersion.RecId == purchTableVersionRecId
           && purchTableVersion.Proforma == NoYes::No                 //only when not proforma, otherwise texts from purchLine will be printed
        join purchLineAllVersions
            where purchLineAllVersions.PurchTableVersionRecId == purchTableVersion.RecId
            join purchLineSource
                where purchLineSource.InventTransId == purchLineAllVersions.InventTransId
                   //&& purchLineSource.IsModified == NoYes::Yes	//otherwise only the textblock of the edited line is copied to the new confirmation, not of each line
    {
        this.parmTargetRecord(purchLineAllVersions);
        this.insertFromSourceRecord(purchLineSource);
    }
}

/// <summary>
/// A <c>PurchLine</c> table was modified and the previous data of <c>PurchLine</c> table is moved to <c>PurchLineHistory</c> table.
/// This method changes the reference from <c>PurchLine</c> table to <c>PurchLineHistory</c> table in <c>FWFTextBlockInstance</c> table .
/// </summary>
/// <param name = "_purchLineHistory">The <c>PurchLineHistory</c> table.</param>
public void arichivatePurchLine(PurchLineHistory _purchLineHistory)
{
    FWFTextBlockInstance textBlockInstance;

    update_recordset textBlockInstance setting RefRecId = _purchLineHistory.RecId, RefTableId = tablenum(PurchLineHistory)
        where textBlockInstance.RefRecId == _purchLineHistory.purchLine().RecId
           && textBlockInstance.RefTableId == tablenum(PurchLineAllVersions);
}

/// <summary>
/// Handles the onInserted event of <c>PurchLineHistory</c> table.
/// </summary>
/// <param name="sender">The <c>PurchLineHistory</c> table that was inserted.</param>
/// <param name="e">The event arguments.</param>
[DataEventHandler(tableStr(PurchLineHistory), DataEventType::Inserted),
    SuppressBPWarningAttribute('BPParameterNotUsed', 'No use for parameter _e')]
public static void PurchLineHistory_onInserted(Common _sender, DataEventArgs _e)
{
    FWFTextBlockEventHandler_Trans_PoConfirm::construct().arichivatePurchLine(_sender as PurchLineHistory);
}
